    logWarning(`Invalid results.repo.remote in ${configPath}, expected non-empty string`);
    return undefined;
  }
  if (remote && !isGitRemoteUrl(remote)) {
    logWarning(`Invalid results.repo.remote in ${configPath}, expected Git remote URL`);
