export async function writeInitialRunSummaryArtifact(
  runDir: string,
  options: {
    evalFile: string;
    plannedTestCount: number;
    experiment?: string;
    experimentMetadata?: ExperimentArtifactMetadata;
    runtimeSource?: RunRuntimeSourceMetadata;
  },
): Promise<void> {
